#include <bits/stdc++.h>
using namespace std;
int main(){
    int sum0=0,sum5=0,n;
    cin>>n;
    for(int i=0;i<n;i++){
        int a;
        cin>>a;
        if(a==0)sum0++;
        else sum5++;
    }
    if(!sum0)cout<<-1;
    else{
        for(int i=0;i<sum5/9*9;i++)cout<<5;
        if(sum5>=9){
            for(int i=0;i<sum0;i++)cout<<0;
        }else{
            cout<<0;
        }
    }
    return 0;
}
